// ─────────────────────────────────────────────────────────────────────────────
// Tuleap sends application/x-www-form-urlencoded with a single 'payload' key
// whose value is a JSON string. This node parses it into a clean structure.
// ─────────────────────────────────────────────────────────────────────────────

const bodyPayload = $input.first().json.body?.payload;
if (!bodyPayload) throw new Error('Missing payload field in request body');

// body.payload may arrive as a string (form-encoded) or already parsed by n8n
const p = typeof bodyPayload === 'string' ? JSON.parse(bodyPayload) : bodyPayload;

// Build a label-keyed map from current changeset values for easy access
const fields = {};
for (const v of (p.current?.values || [])) {
  fields[v.label] = v;
}

// ── Assignee (type: sb — user select box, gives full user object) ────────────
const assignee = fields['Assigned to']?.values?.[0] || null;

// ── Status (type: sb — static values list) ───────────────────────────────────
const tuleapStatus = fields['Status']?.values?.[0]?.label || 'Todo';

// ── Team (type: sb — may have multiple values e.g. QA-Team, Dev-Team) ────────
const teamNames = (fields['Team']?.values || []).map(v => v.label);

const TULEAP_BASE = 'https://tuleap.windinfosys.com';

return [{
  json: {
    // ── Identifiers ──────────────────────────────────────────────────────────
    artifactId:        p.id,
    trackerId:         p.tracker?.id,
    trackerItemName:   p.tracker?.item_name,
    tuleapProjectId:   p.tracker?.project?.id,
    tuleapProjectName: p.tracker?.project?.label,
    tuleapAction:      p.action,          // 'create', 'update' or 'delete'
    tuleapUrl:         `${TULEAP_BASE}/plugins/tracker/?aid=${p.id}`,

    // ── Task content ─────────────────────────────────────────────────────────
    taskTitle:    fields['Task title']?.value  || null,
    description:  fields['Description']?.value || null,
    tuleapStatus,
    blockedReason: fields['Blocked Reason']?.value || null,

    // ── Team filter (used by Match Config to skip non-QA tasks) ──────────────
    teamNames,   // e.g. ['QA-Team'] or ['Dev-Team'] or []

    // ── Hours ─────────────────────────────────────────────────────────────────
    pmEstimate:   fields['PM Final Estimate (Hours)']?.value   ?? null,
    devEstimate:  fields['Dev Initial Estimate (Hours)']?.value ?? null,
    actualEffort: fields['Actual Effort']?.value               ?? null,

    // ── Dates ─────────────────────────────────────────────────────────────────
    submittedOn:  fields['Submitted on']?.value    || null,
    lastModified: p.current?.last_modified_date    || null,

    // ── Assignee details (all available for flexible resource matching) ───────
    assigneeId:          assignee?.id                    || null,
    assigneeUsername:    assignee?.username               || null,
    assigneeRealName:    assignee?.real_name?.trim()      || null,
    assigneeDisplayName: assignee?.display_name           || null,
    assigneeEmail:       assignee?.email                  || null,

    // ── Linked artifacts ─────────────────────────────────────────────────────
    parentStoryId: fields['Parent Story']?.reverse_links?.[0]?.id || null,

    // ── Audit ─────────────────────────────────────────────────────────────────
    changedBy:   p.user?.username || null,
    rawPayload:  p
  }
}];

const parsed  = $('Parse Payload').first().json;
const configs = $input.first().json.data || [];

const teamNames    = parsed.teamNames || [];
const isWrongTeam  = teamNames.length > 0 && !teamNames.includes('QA-Team');
const tuleapAction = (parsed.tuleapAction || '').toLowerCase();

// Team changed away from QA-Team on an existing task → force-delete from QC
if (isWrongTeam && (tuleapAction === 'update' || tuleapAction === 'delete')) {
  const config = configs.find(c =>
    String(c.tuleap_tracker_id) === String(parsed.trackerId) &&
    String(c.tuleap_project_id) === String(parsed.tuleapProjectId)
  );
  return [{ json: {
    configFound: true,
    config: config || {},
    forceDelete: true,
    forceReason: `Team changed to [${teamNames.join(', ')}] — task removed from QC`
  }}];
}

// New task created with wrong team → skip entirely, don't touch QC
if (isWrongTeam) {
  return [{ json: {
    configFound: false,
    reason: `Skipped: task belongs to [${teamNames.join(', ')}], not QA-Team`
  }}];
}

// Normal flow: match sync config by tracker + project
const config = configs.find(c =>
  String(c.tuleap_tracker_id) === String(parsed.trackerId) &&
  String(c.tuleap_project_id) === String(parsed.tuleapProjectId)
);

if (!config) {
  return [{ json: {
    configFound: false,
    reason: `No active sync config for tracker ${parsed.trackerId} in Tuleap project ${parsed.tuleapProjectId} (${parsed.tuleapProjectName})`
  }}];
}

return [{ json: { configFound: true, config } }];

const parsed      = $('Parse Payload').first().json;
const matchResult = $('Match Config').first().json;
const config      = matchResult.config;
const resources   = $('Fetch All Resources').first().json.data || [];

// ── Force-delete: team changed away from QA-Team ─────────────────────────────
if (matchResult.forceDelete) {
  return [{
    json: {
      action:             'delete',
      tuleap_artifact_id: parsed.artifactId,
      tuleap_url:         parsed.tuleapUrl,
      task_name:          parsed.taskTitle,
      notes:              null,
      resource1_id:       null,
      new_assignee_name:  parsed.assigneeDisplayName,
      project_id:         config?.qc_project_id || null,
      action_reason:      matchResult.forceReason,
      raw_tuleap_payload: parsed.rawPayload,
      _debug: { forceDelete: true, teams: parsed.teamNames }
    }
  }];
}

// ── Normal flow ───────────────────────────────────────────────────────────────
const email    = (parsed.assigneeEmail    || '').toLowerCase().trim();
const realName = (parsed.assigneeRealName || '').toLowerCase().trim();
const uname    = (parsed.assigneeUsername || '').toLowerCase().trim();

const resource = resources.find(r => {
  const re = (r.email         || '').toLowerCase().trim();
  const rn = (r.resource_name || '').toLowerCase().trim();
  return (email    && re === email)    ||
         (realName && rn === realName) ||
         (uname    && rn === uname);
}) || null;

const tuleapAction = (parsed.tuleapAction || '').toLowerCase();
const qcAction = tuleapAction === 'delete' ? 'delete'
               : tuleapAction === 'create' ? 'create'
               : 'update';

const STATUS_MAP = {
  'Todo':        'Backlog',
  'In Progress': 'In Progress',
  'Blocked':     'In Progress',
  'Done':        'Done',
  'Canceled':    'Cancelled'
};

return [{
  json: {
    action:             qcAction,
    tuleap_artifact_id: parsed.artifactId,
    tuleap_url:         parsed.tuleapUrl,
    task_name:          parsed.taskTitle,
    notes:              parsed.description || null,
    tuleap_status:      parsed.tuleapStatus,
    resource1_id:       resource?.id       || null,
    new_assignee_name:  parsed.assigneeDisplayName,
    project_id:         config?.qc_project_id || null,
    action_reason:      null,
    raw_tuleap_payload: parsed.rawPayload,
    _debug: {
      matchedResource: resource ? { id: resource.id, name: resource.resource_name } : null,
      resourceMatched: !!resource,
      tuleapAction:    parsed.tuleapAction,
      qcAction,
      tuleapStatus:    parsed.tuleapStatus,
      mappedStatus:    STATUS_MAP[parsed.tuleapStatus] || 'Backlog',
    }
  }
}];
